mapper.select:
select m.id, m.major_code, m.major_name, m.category_dict_item_id, d.dict_label as category_label
and (m.major_code like concat('%', #{keyword}, '%') or m.major_name like concat('%', #{keyword}, '%') or d.dict_label like concat('%', #{keyword}, '%'))
order by m.major_name limit #{offset}, #{limit}

select m.id, m.major_code, m.major_name, m.category_dict_item_id, d.dict_label as category_label

  and m.id = #{id}
limit 1

select m.id, m.major_code, m.major_name, m.category_dict_item_id, d.dict_label as category_label

  and m.major_code = #{majorCode}
limit 1

select m.id, m.major_code, m.major_name, m.category_dict_item_id, d.dict_label as category_label

  and m.major_name = #{majorName}
limit 1

mapper.update:
update sys_major_catalog
set major_code = #{majorCode},
    major_name = #{majorName},
    category_dict_item_id = #{categoryDictItemId}
where id = #{id}
  and deleted = 0
